(1,1,'Starting a Conversation','เริ่มบทสนทนา',$json$[{"word":"hello","phonetic":"เฮลโล","meaning":"สวัสดี","partOfSpeech":"interjection"},{"word":"name","phonetic":"เนม","meaning":"ชื่อ","partOfSpeech":"noun"},{"word":"nice","phonetic":"ไนซ์","meaning":"ดี / ยินดี","partOfSpeech":"adjective"},{"word":"meet","phonetic":"มีท","meaning":"พบ / เจอ","partOfSpeech":"verb"},{"word":"how","phonetic":"ฮาว","meaning":"อย่างไร / เป็นไง","partOfSpeech":"adverb"},{"word":"fine","phonetic":"ไฟน์","meaning":"สบายดี","partOfSpeech":"adjective"},{"word":"friend","phonetic":"เฟรนด์","meaning":"เพื่อน","partOfSpeech":"noun"}]$json$::jsonb,$json$[[{"english":"Bam","thai":"แบม"},{"english":"walks","thai":"วอล์คส"},{"english":"into","thai":"อินทู"},{"english":"a","thai":"อะ"},{"english":"cafe.","thai":"คาเฟ่"}],[{"english":"She","thai":"ชี"},{"english":"sees","thai":"ซีส"},{"english":"Fon.","thai":"ฟน"}],[{"english":"\"Hello!","thai":"เฮลโล"},{"english":"My","thai":"มาย"},{"english":"name","thai":"เนม"},{"english":"is","thai":"อิส"},{"english":"Bam.\"","thai":"แบม"}],[{"english":"\"Nice","thai":"ไนซ์"},{"english":"to","thai":"ทู"},{"english":"meet","thai":"มีท"},{"english":"you!","thai":"ยู"},{"english":"I","thai":"ไอ"},{"english":"am","thai":"แอม"},{"english":"Fon.\"","thai":"ฟน"}],[{"english":"\"How","thai":"ฮาว"},{"english":"are","thai":"อาร์"},{"english":"you?\"","thai":"ยู"}],[{"english":"\"I","thai":"ไอ"},{"english":"am","thai":"แอม"},{"english":"fine!","thai":"ไฟน์"},{"english":"Let''s","thai":"เล็ทส์"},{"english":"be","thai":"บี"},{"english":"friends.\"","thai":"เฟรนด์ส"}]]$json$::jsonb,'แบมเดินเข้าไปในคาเฟ่ เธอเห็นฟน "สวัสดี! ฉันชื่อแบม" "ยินดีที่ได้เจอ! ฉันชื่อฟน" "เป็นไงบ้าง?" "ฉันสบายดี! มาเป็นเพื่อนกันเถอะ"','Two young Thai women meeting for the first time at a cozy Bangkok cafe, smiling and waving hello, warm pastel colors, cute illustration style',$json$[{"question":"\"nice\" แปลว่าอะไร?","options":["สวัสดี","ดี / ยินดี","ชื่อ","เพื่อน"],"correctIndex":1,"type":"vocab"},{"